const caches=new WeakMap,createEmptyCache=()=>({definitions:new Map,usage:new Map,importLookup:new Map,exportedIdentifiers:new Map,generation:0}),getCache=e=>{let t=caches.get(e);return t||(t=createEmptyCache(),caches.set(e,t)),t};export const invalidateCache=e=>{const t=caches.get(e);t&&(t.definitions.clear(),t.usage.clear(),t.importLookup.clear(),t.exportedIdentifiers.clear(),t.generation++)};export const getCachedDefinition=(e,t,n)=>{const s=caches.get(e);if(!s)return;const c=s.definitions.get(t);return c&&c.has(n)?c.get(n):void 0};export const setCachedDefinition=(e,t,n,s)=>{const c=getCache(e);let a=c.definitions.get(t);a||(a=new Map,c.definitions.set(t,a)),a.set(n,s)};export const getCachedUsage=(e,t,n)=>{const s=caches.get(e);if(!s)return;const c=s.usage.get(t);return c?c.get(n):void 0};export const setCachedUsage=(e,t,n,s)=>{const c=getCache(e);let a=c.usage.get(t);a||(a=new Map,c.usage.set(t,a)),a.set(n,s)};export const getCachedExportedIdentifiers=(e,t)=>{const n=caches.get(e);if(n)return n.exportedIdentifiers.get(t)};export const setCachedExportedIdentifiers=(e,t,n)=>{getCache(e).exportedIdentifiers.set(t,n)};